// utils.js
export const BASE_URL = 'https://api.example.com'

export function formatDate(date) {
  return new Intl.DateTimeFormat('en-US', {
    year: 'numeric', month: 'short', day: 'numeric'
  }).format(date)
}

export function formatCurrency(amount, currency = 'USD') {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency }).format(amount)
}

// export at bottom (common — lets you define first, export separately)
function helperA() { /* ... */ }
function helperB() { /* ... */ }
export { helperA, helperB }

// ── default export ────────────────────────────────────────
// only one per file — usually the main thing the file is about
export default class ApiClient {
  constructor(baseUrl, options = {}) {
    this.baseUrl = baseUrl
    this.headers = options.headers ?? {}
  }

  async get(path)         { return this.#request('GET',    path) }
  async post(path, body)  { return this.#request('POST',   path, body) }
  async put(path, body)   { return this.#request('PUT',    path, body) }
  async delete(path)      { return this.#request('DELETE', path) }

  async #request(method, path, body) {
    const res = await fetch(`${this.baseUrl}${path}`, {
      method,
      headers: { 'Content-Type': 'application/json', ...this.headers },
      body: body ? JSON.stringify(body) : undefined,
    })
    if (!res.ok) throw new Error(`${method} ${path} → ${res.status}`)
    return res.json()
  }
}

// ── import styles ─────────────────────────────────────────
import ApiClient                    from './api-client.js'      // default
import { formatDate, BASE_URL }     from './utils.js'           // named
import { formatDate as fmt }        from './utils.js'           // renamed
import * as utils                   from './utils.js'           // namespace object
import ApiClient, { BASE_URL }      from './api-client.js'      // both at once

// ── barrel file (index.js) ────────────────────────────────
// lets consumers import from one place instead of deep paths
// components/index.js
export { Button }         from './Button.js'
export { Input }          from './Input.js'
export { Modal }          from './Modal.js'
export { default as Card} from './Card.js'   // re-export default as named

// consumer
import { Button, Modal, Card } from './components/index.js'

// ── dynamic import — load on demand ──────────────────────
// the module is only fetched and parsed when this line runs
async function loadChartLib() {
  const { default: Chart } = await import('./chart.js')
  return new Chart(document.getElementById('canvas'))
}

// conditional load
async function loadDevTools() {
  if (process.env.NODE_ENV === 'development') {
    const { setup } = await import('./dev-tools.js')
    setup()
  }
}</code></pre>
