const maybeUsers: (User | null)[] = [user1, null, user2, null, user3]
const users = maybeUsers.filter(isNonNull)  // User[] — not (User | null)[]

// ── assertion function ────────────────────────────────────
// tells TS: after this call, condition is definitely true
function assert(condition: unknown, message: string): asserts condition {
  if (!condition) throw new Error(message)
}

function assertIsString(val: unknown): asserts val is string {
  if (typeof val !== 'string') throw new TypeError(`Expected string, got ${typeof val}`)
}

