async function fetchUser(id) {
  const res = await fetch(`/api/users/${id}`)
  if (!res.ok) throw new Error(`HTTP ${res.status}: ${res.statusText}`)
  return res.json()
}

// always handle errors — unhandled rejections will bite you
async function loadUser(id) {
  try {
    const user = await fetchUser(id)
    return { data: user, error: null }
  } catch (err) {
    return { data: null, error: err.message }
  }
}

// ── Promise.all — parallel, fails if any fail ────────────
async function loadDashboard(userId) {
  const [user, posts, notifications] = await Promise.all([
    fetchUser(userId),
    fetch(`/api/users/${userId}/posts`).then(r => r.json()),
    fetch('/api/notifications').then(r => r.json()),
  ])
  return { user, posts, notifications }
}

// ── Promise.allSettled — parallel, never fails ───────────
// use this when you want all results even if some fail
async function loadMultipleUsers(ids) {
  const results = await Promise.allSettled(ids.map(fetchUser))

  return results.map((result, i) => ({
    id: ids[i],
    user:  result.status === 'fulfilled' ? result.value     : null,
    error: result.status === 'rejected'  ? result.reason.message : null,
  }))
}

// ── Promise.race — first one wins ────────────────────────
function withTimeout(promise, ms = 5000) {
  const timeout = new Promise((_, reject) =>
    setTimeout(() => reject(new Error(`Timed out after ${ms}ms`)), ms)
  )
  return Promise.race([promise, timeout])
}

const user = await withTimeout(fetchUser(1), 3000)

// ── building promises manually ───────────────────────────
function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms))
}

function toPromise(fn) {
  return new Promise((resolve, reject) => {
    fn((err, result) => err ? reject(err) : resolve(result))
  })
}

// ── retry with backoff ────────────────────────────────────
async function retry(fn, { attempts = 3, waitMs = 500 } = {}) {
  let lastError

  for (let i = 0; i < attempts; i++) {
    try {
      return await fn()
    } catch (err) {
      lastError = err
      if (i < attempts - 1) await delay(waitMs * 2 ** i)  // exponential backoff
    }
  }

  throw lastError
}

const data = await retry(() => fetchUser(1), { attempts: 3, waitMs: 1000 })

// ── async iteration ──────────────────────────────────────
async function* paginate(baseUrl) {
  let page = 1
  while (true) {
    const res  = await fetch(`${baseUrl}?page=${page}`)
    const json = await res.json()
    if (!json.data.length) break
    yield json.data
    if (!json.hasMore) break
    page++
  }
}

