import { formatDate, BASE_URL }     from './utils.js'           // named
import { formatDate as fmt }        from './utils.js'           // renamed
import * as utils                   from './utils.js'           // namespace object
import ApiClient, { BASE_URL }      from './api-client.js'      // both at once

// ── barrel file (index.js) ────────────────────────────────
// lets consumers import from one place instead of deep paths
// components/index.js
export { Button }         from './Button.js'
export { Input }          from './Input.js'
export { Modal }          from './Modal.js'
export { default as Card} from './Card.js'   // re-export default as named

// consumer
import { Button, Modal, Card } from './components/index.js'

