function formatValue(value: string | number | boolean) {
  if (typeof value === 'string')  return value.toUpperCase()
  if (typeof value === 'number')  return value.toFixed(2)
  return value ? 'yes' : 'no'
}

// ── instanceof narrowing ──────────────────────────────────
function handleError(err: unknown): string {
  if (err instanceof Error)       return err.message
  if (typeof err === 'string')    return err
  return 'Unknown error'
}

// ── in-operator narrowing ─────────────────────────────────
interface Cat  { type: 'cat'; meow(): void }
interface Dog  { type: 'dog'; bark(): void }
interface Bird { fly(): void; wingspan: number }

function makeSound(animal: Cat | Dog) {
  if ('meow' in animal) animal.meow()  // Cat
  else                  animal.bark()  // Dog
}

// ── custom type guard — predicate function ────────────────
function isCat(animal: Cat | Dog): animal is Cat {
  return animal.type === 'cat'
}

function isError(value: unknown): value is Error {
  return value instanceof Error
}

function isNonNull&lt;T&gt;(value: T | null | undefined): value is T {
  return value != null
}

// filter out nulls with type safety
const maybeUsers: (User | null)[] = [user1, null, user2, null, user3]
const users = maybeUsers.filter(isNonNull)  // User[] — not (User | null)[]

// ── assertion function ────────────────────────────────────
// tells TS: after this call, condition is definitely true
function assert(condition: unknown, message: string): asserts condition {
  if (!condition) throw new Error(message)
}

function assertIsString(val: unknown): asserts val is string {
  if (typeof val !== 'string') throw new TypeError(`Expected string, got ${typeof val}`)
}

function getUser(id: number, users: User[]): User {
  const user = users.find(u => u.id === id)
  assert(user !== undefined, `User ${id} not found`)
  return user  // User — TS no longer thinks it could be undefined
}

// ── satisfies operator (TS 4.9+) ─────────────────────────
// validates shape but keeps the inferred literal types
const config = {
  port:  3000,
  host: 'localhost',
  env:  'development',
} satisfies { port: number; host: string; env: string }

