        <pre><code class="language-ts">// deno run --allow-net server.ts

// ── minimal ───────────────────────────────────────────────
Deno.serve({ port: 8000 }, (req: Request) =&gt; {
  const url = new URL(req.url)

  if (url.pathname === '/')     return new Response('Hello Deno')
  if (url.pathname === '/ping') return Response.json({ pong: true })

  return new Response('Not Found', { status: 404 })
})

// ── router pattern without a framework ───────────────────
type Handler = (req: Request, params?: Record&lt;string, string&gt;) =&gt;
  Response | Promise&lt;Response&gt;

const routes = new Map&lt;string, Handler&gt;()

function route(method: string, path: string, handler: Handler) {
  routes.set(`${method} ${path}`, handler)
}

route('GET',  '/',         ()    =&gt; Response.json({ status: 'ok' }))
route('GET',  '/users',    ()    =&gt; Response.json([{ id: 1, name: 'Alex' }]))
route('POST', '/users',    async (req) =&gt; {
  const body = await req.json()
  return Response.json({ id: 2, ...body }, { status: 201 })
})

Deno.serve({ port: 8000 }, (req: Request) =&gt; {
  const url    = new URL(req.url)
  const key    = `${req.method} ${url.pathname}`
  const handler = routes.get(key)

  if (!handler) return new Response('Not Found', { status: 404 })

  try {
    return handler(req)
  } catch (err) {
